// src/pages/Dashboard/DashboardPage.js
import React, { useState, useEffect } from 'react';
import {
  Users, Clock, CalendarDays, CreditCard,
  TrendingUp, TrendingDown, CheckCircle, AlertCircle,
  UserCheck, Timer, DollarSign, Calendar,
} from 'lucide-react';
import { attendanceAPI, leaveAPI, payrollAPI, employeeAPI } from '../../api/services';
import { SkeletonCard } from '../../components/common';
import { useAuth } from '../../context/AuthContext';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

const COLORS = ['#f0b429','#3b82f6','#22c55e','#ef4444','#a855f7','#06b6d4'];

function KpiCard({ icon: Icon, color, label, value, trend, trendLabel, loading }) {
  if (loading) return <SkeletonCard />;
  return (
    <div className="stat-card" style={{ cursor: 'default' }}>
      <div className="stat-card-accent" style={{ background: color }} />
      <div className="flex items-center justify-between mb-4" style={{ marginBottom: 14 }}>
        <div className="stat-card-icon" style={{ background: `${color}22`, marginBottom: 0 }}>
          <Icon size={20} style={{ color }} />
        </div>
        {trend !== undefined && (
          <span className={trend >= 0 ? 'trend-up' : 'trend-down'}>
            {trend >= 0 ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
            {' '}{Math.abs(trend)}%
          </span>
        )}
      </div>
      <div className="stat-card-value">{value ?? '—'}</div>
      <div className="stat-card-label">{label}</div>
      {trendLabel && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: 4 }}>{trendLabel}</div>}
    </div>
  );
}

export default function DashboardPage() {
  const { user } = useAuth();
  const [kpis, setKpis]       = useState(null);
  const [today, setToday]     = useState(null);
  const [balances, setBalances] = useState([]);
  const [payDash, setPayDash] = useState(null);
  const [activity, setActivity] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.allSettled([
      attendanceAPI.getDashboardKPIs(),
      attendanceAPI.getTodayStatus(),
      leaveAPI.getMyBalances(),
      payrollAPI.getDashboard().catch(() => null),
      attendanceAPI.getRecentActivity(),
    ]).then(([k, t, b, p, a]) => {
      if (k.status === 'fulfilled') setKpis(k.value?.data);
      if (t.status === 'fulfilled') setToday(t.value?.data);
      if (b.status === 'fulfilled') setBalances(b.value?.data?.balances || b.value?.data || []);
      if (p.status === 'fulfilled' && p.value) setPayDash(p.value?.data);
      if (a.status === 'fulfilled') setActivity(a.value?.data?.activities || a.value?.data || []);
      setLoading(false);
    });
  }, []);

  const displayName = user
    ? (user.firstName ? user.firstName : user.name?.split(' ')[0] || 'there')
    : 'there';

  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';

  // Build leave chart data
  const leaveChartData = balances.slice(0,6).map(b => ({
    name:  b.leaveTypeName || b.name || b.type,
    used:  b.usedDays ?? b.used ?? 0,
    left:  b.remainingDays ?? b.remaining ?? 0,
  }));

  return (
    <>
      {/* Greeting */}
      <div className="page-header">
        <h1>{greeting}, {displayName} 👋</h1>
        <p>Here's what's happening in your workspace today — {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</p>
      </div>

      {/* KPI Row */}
      <div className="grid-4" style={{ marginBottom: 28 }}>
        <KpiCard loading={loading} icon={UserCheck} color="var(--blue)"   label="Present Today"     value={kpis?.presentToday    ?? today?.status} />
        <KpiCard loading={loading} icon={Timer}     color="var(--green)"  label="Avg. Hours / Day"   value={kpis?.avgHoursPerDay  ? `${kpis.avgHoursPerDay}h` : kpis?.attendanceRate ? `${kpis.attendanceRate}%` : '—'} trendLabel="This month" />
        <KpiCard loading={loading} icon={Calendar}  color="var(--amber)"  label="Pending Leaves"     value={kpis?.pendingLeaves   ?? '—'} />
        <KpiCard loading={loading} icon={DollarSign} color="var(--purple)" label="Payroll Runs"       value={payDash?.totalRuns   ?? payDash?.activeRuns ?? '—'} trendLabel="Active runs" />
      </div>

      {/* Charts Row */}
      <div className="grid-2" style={{ marginBottom: 28 }}>
        {/* Leave Balances Chart */}
        <div className="card">
          <div className="card-header">
            <div>
              <div className="card-title">Leave Balances</div>
              <div className="card-subtitle">Days remaining by type</div>
            </div>
          </div>
          {loading ? (
            <div className="skeleton" style={{ height: 180 }} />
          ) : leaveChartData.length > 0 ? (
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={leaveChartData} margin={{ top: 5, right: 5, bottom: 5, left: -20 }}>
                <XAxis dataKey="name" tick={{ fontSize: 11, fill: 'var(--text-secondary)' }} />
                <YAxis tick={{ fontSize: 11, fill: 'var(--text-secondary)' }} />
                <Tooltip
                  contentStyle={{ background: 'var(--bg-elevated)', border: '1px solid var(--border)', borderRadius: 8, fontSize: 12 }}
                  labelStyle={{ color: 'var(--text-primary)' }}
                />
                <Bar dataKey="left"  fill="var(--gold)"  radius={[4,4,0,0]} name="Remaining" />
                <Bar dataKey="used"  fill="var(--border)" radius={[4,4,0,0]} name="Used" />
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div style={{ height: 200, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', fontSize: '0.85rem' }}>
              No leave data available
            </div>
          )}
        </div>

        {/* Today's Status */}
        <div className="card">
          <div className="card-header">
            <div>
              <div className="card-title">Today's Status</div>
              <div className="card-subtitle">Your attendance for today</div>
            </div>
            {today && (
              <span className={`badge ${today.checkedIn ? 'badge-approved' : 'badge-pending'}`}>
                {today.checkedIn ? 'Checked In' : today.status || 'Not Checked In'}
              </span>
            )}
          </div>

          {loading ? (
            <>
              <div className="skeleton skeleton-text w-60" />
              <div className="skeleton skeleton-text w-40" style={{ marginTop: 8 }} />
            </>
          ) : today ? (
            <div>
              {[
                { label: 'Check-In',      value: today.checkInTime  || today.checkedInAt  || '—' },
                { label: 'Check-Out',     value: today.checkOutTime || today.checkedOutAt || '—' },
                { label: 'Hours Worked',  value: today.hoursWorked  ? `${today.hoursWorked}h` : '—' },
                { label: 'Status',        value: today.status || (today.checkedIn ? 'Present' : 'Absent') },
                { label: 'Shift',         value: today.shiftName || today.shift || '—' },
              ].map(({ label, value }) => (
                <div className="info-row" key={label}>
                  <span className="info-row-label">{label}</span>
                  <span className="info-row-value">{value}</span>
                </div>
              ))}
            </div>
          ) : (
            <div style={{ color: 'var(--text-muted)', fontSize: '0.85rem', textAlign: 'center', padding: 30 }}>
              No attendance data for today
            </div>
          )}
        </div>
      </div>

      {/* Recent Activity */}
      <div className="card">
        <div className="card-header">
          <div className="card-title">Recent Activity</div>
        </div>
        {loading ? (
          <div className="skeleton" style={{ height: 120 }} />
        ) : activity.length > 0 ? (
          <div className="timeline" style={{ maxHeight: 300, overflowY: 'auto' }}>
            {activity.slice(0, 8).map((item, i) => (
              <div className="timeline-item" key={i}>
                <div className="timeline-dot" style={{ background: COLORS[i % COLORS.length] }} />
                <div className="timeline-line" />
                <div className="timeline-content">
                  <div className="timeline-title">{item.description || item.action || item.message || JSON.stringify(item)}</div>
                  <div className="timeline-meta">
                    {item.employeeName && `${item.employeeName} · `}
                    {item.createdAt ? new Date(item.createdAt).toLocaleString() : item.time || ''}
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={{ color: 'var(--text-muted)', fontSize: '0.85rem', textAlign: 'center', padding: 30 }}>
            No recent activity
          </div>
        )}
      </div>
    </>
  );
}
